/* Lee productos directamente del nodo Consultar stock critico.
   El endpoint devuelve un array JSON plano. */
var resp = $node["Consultar stock critico"].json;
var productosCriticos = Array.isArray(resp) ? resp : (resp.productos || resp.data || []);

if (!productosCriticos || productosCriticos.length === 0) {
  return [];
}

var productosFormato = productosCriticos.map(function(p) {
  return {
    _id: p._id,
    nombre: p.nombre || "Producto",
    descripcion: p.descripcion || "",
    stock: p.stock || 0,
    umbral: p.umbral != null ? p.umbral : (p.umbralCritico != null ? p.umbralCritico : 5),
    precio: p.precio || 0
  };
});

var productosDetalle = productosFormato
  .map(function(p) {
    return p.nombre + " (Stock: " + p.stock + ", umbral: " + p.umbral + ")";
  })
  .join("; ");

var mensaje = "ALERTA STOCK CRITICO: " + productosFormato.length
  + " producto(s) con stock bajo. " + productosDetalle;

return [{ json: {
  mensaje: mensaje,
  productos: productosFormato,
  tipo: "stock_critico",
  cantidad: productosFormato.length
} }];

/* Extrae del body del webhook: decision, idNotificacion, productos, mensaje */
var data = $json.body || $json;
var decision = (data.decision || "").toLowerCase().trim();
var idNotificacion = data.idNotificacion || data.id || "";
var productos = Array.isArray(data.productos) ? data.productos : [];
var mensaje = data.mensaje || "";

// Flag silencioso — no lanza excepcion para que el webhook siempre responda
var valid = (idNotificacion !== '' && decision !== '');

return [{ json: { decision: decision, idNotificacion: idNotificacion, productos: productos, mensaje: mensaje, valid: valid } }];

/* Construye el asunto y cuerpo del email para el proveedor.
   Usa los productos que vienen de Normalizar datos admin. */
var productos = $json.productos || [];
var idNotificacion = $json.idNotificacion || "";
var ahora = new Date();
var opciones = { timeZone: "America/Guayaquil", day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" };
var fechaStr = ahora.toLocaleDateString("es-EC", opciones);

var listaProductos = productos.length > 0
  ? productos.map(function(p) {
      return "  - " + p.nombre
        + " | Stock actual: " + p.stock + " unidades"
        + " | Umbral minimo: " + (p.umbral || 5) + " unidades"
        + (p.descripcion ? " | " + p.descripcion : "");
    }).join("\n")
  : "  - (Ver detalle en el sistema Unitex)";

var asunto = "Solicitud de reposicion de stock - Unitex - " + ahora.toLocaleDateString("es-EC", { timeZone: "America/Guayaquil", day: "2-digit", month: "2-digit", year: "numeric" });

var cuerpo = [
  "Estimado proveedor,",
  "",
  "Le informamos que tras la revision automatica de inventario del " + fechaStr + ",",
  "los siguientes productos requieren reposicion urgente:",
  "",
  listaProductos,
  "",
  "Solicitamos amablemente confirmar:",
  "  1. Disponibilidad de los productos listados",
  "  2. Cantidad maxima disponible para entrega inmediata",
  "  3. Tiempo estimado de entrega",
  "  4. Precio unitario actualizado si hubiera cambios",
  "",
  "Este pedido fue aprobado por el administrador de Unitex y generado",
  "automaticamente por nuestro sistema de monitoreo de inventario.",
  "",
  "Quedamos atentos a su respuesta.",
  "",
  "Saludos cordiales,",
  "Sistema Unitex - Gestion de Inventario",
  "Referencia de gestion: " + idNotificacion,
  "Fecha: " + fechaStr
].join("\n");

return [{ json: {
  asunto: asunto,
  cuerpo: cuerpo,
  idNotificacion: idNotificacion,
  productos: productos,
  cantidadProductos: productos.length
} }];

/* Resumen cuando el admin APROBO la solicitud */
var norm = $node["Normalizar datos admin"].json;
var ahora = new Date();
var fecha = ahora.toLocaleDateString("es-EC", {
  timeZone: "America/Guayaquil", day: "2-digit", month: "2-digit", year: "numeric",
  hour: "2-digit", minute: "2-digit"
});
var cantProd = Array.isArray(norm.productos) ? norm.productos.length : 0;
var resumen = [
  "=== RESUMEN GESTION UNITEX ===",
  "Fecha: " + fecha,
  "Notificacion ID: " + norm.idNotificacion,
  "Decision admin: APROBADO",
  "Productos gestionados: " + cantProd,
  "Email enviado al proveedor: SI",
  "Estado final: Completado",
  "=============================="
].join("\n");
return [{ json: { resumen: resumen, decision: "aprobado", idNotificacion: norm.idNotificacion, cantidadProductos: cantProd, emailEnviado: true } }];

/* Resumen cuando el admin RECHAZO la solicitud */
var norm = $json;
var ahora = new Date();
var fecha = ahora.toLocaleDateString("es-EC", {
  timeZone: "America/Guayaquil", day: "2-digit", month: "2-digit", year: "numeric",
  hour: "2-digit", minute: "2-digit"
});
var cantProd = Array.isArray(norm.productos) ? norm.productos.length : 0;
var resumen = [
  "=== RESUMEN GESTION UNITEX ===",
  "Fecha: " + fecha,
  "Notificacion ID: " + norm.idNotificacion,
  "Decision admin: RECHAZADO",
  "Productos afectados: " + cantProd,
  "Email enviado al proveedor: NO",
  "Estado final: Cancelado por admin",
  "=============================="
].join("\n");
return [{ json: { resumen: resumen, decision: "rechazado", idNotificacion: norm.idNotificacion, cantidadProductos: cantProd, emailEnviado: false } }];
